<template>
  <div class="content">
    <h2
      :class="isHome ? 'sr-only' : 'sub'"
      class="page-title"
    >{{ pageTitle }}</h2>
    <div
      class="grid"
      :class="grid ? 'grid-3' : 'grid-1'"
    >
      <div
        v-for="(video, i) in fetchedVideos"
        :key="i"
        class="film"
        id="video"
      >
        <router-link :to="{ 
          name: videoRouteName, 
          params: { vid: video.video_id, slug: slugify(video.title), title: video.title, directorSlug: slugify(pageTitle) }}
        ">
          <figure>
            <img
              :src="video[isHome ? imgHQ : imgLQ]"
              :alt="video.title"
              class="thumbnail"
            >
          </figure>
          <span class="details">
            <span class="title">
              {{video.title}}
            </span>
            <span class="description">{{video.description}}</span>
          </span>
        </router-link>
      </div>
    </div>
  </div>
</template>
<script>
  import { ref, inject, onMounted, watch } from 'vue'
  import { useRoute, useRouter } from 'vue-router'
  import { films } from '../films.json'

  export default {
    props: {
      source: {
        type: String,
        default: 'film'
      },
      grid: {
        type: Boolean,
        default: true,
      }
    },
    setup(props) {
      const route = useRoute()
      const router = useRouter()
      const slugify = inject('slugify')
      const isHome = props.source === 'home'
      // const fetchData = inject('fetchData')
      const sessionData = JSON.parse(sessionStorage.getItem("data"))
      const fetchedVideos = isHome ? sessionData : sessionData
      const currentDirector = Object.keys(films.director).find(e => slugify(e) === route.params.slug)
      // const dataArray = ref(currentDirector ? films.director[currentDirector] : films[route.name.toLowerCase()])
      const pageTitle = ref(route.meta.title ? route.meta.title : currentDirector)
      const videoRouteName = route.name === 'Director' ? 'Director Video' : 'Video'

      onMounted(async () => {
        // await fetchData(films)
        router.push({ params: { title: pageTitle.value }})
      })

      watch(
          () => route.name,
          () => {
          pageTitle.value = route.meta.title ? route.meta.title : currentDirector
      })

      /*
      router.afterEach(() => {
          pageTitle.value = route.meta.title ? route.meta.title : currentDirector
      });
      */
     // router.beforeEach(() => fetchData = null);

      return {
        fetchedVideos,
        videoRouteName,
        slugify,
        pageTitle,
        isHome
      }
    }
  }
</script>