import { createApp } from 'vue'
import App from './App.vue'
import router from './router'
import { films } from './films.json'

function slugify(s) {
	return s.toString().normalize('NFD').replace(/[\u0300-\u036f]/g, "") //remove diacritics
		.toLowerCase()
		.replace(/\s+/g, '-') //spaces to dashes
		.replace(/[^\w-]+/g, '') //remove non-words
		.replace(/--+/g, '-') //collapse multiple dashes
		.replace(/^-+/, '') //trim starting dash
		.replace(/-+$/, ''); //trim ending dash
}

const fetchData = async (obj, store = {}) => {
	const token = '6ca7dc0633b646b2abba1c4d28a14a6d'
	const filter = 'fields=name,description,pictures.uri'
	const lq = '_640x360'
	const hq = '_1920x1080'
	const imgUri = (uri, quality) => 'https://i.vimeocdn.com/video/'.concat(uri.split('/').pop(), quality, '.webp')
	const fetchUri = (videoIds) => `https://api.vimeo.com/videos?uris=${videoIds}&access_token=${token}&${filter}`

	await Promise.resolve(Object.entries(obj).forEach(async ([key, value]) => {
		if (key != 'director') {
			// Get all VimeoIds
			const videoIds = value.map(id => `/videos/${id}`).join(',')

			// Fetch from API
			const res = await (await fetch(fetchUri(videoIds))).json()

			// Create a cleaner object
			Object.values(res.data).map((val) => {
				val.slug = slugify(val.name)
				val.imgLQ = imgUri(val.pictures.uri, lq)
				val.imgHQ = imgUri(val.pictures.uri, hq)
				delete val.pictures;
			})

			// Remove irrelevant data
			// eslint-disable-next-line no-unused-vars
			const { total, page, per_page, paging, ...rest } = res;

			// Save
			store[key] = await { ...rest.data }
		}
		else {
			store[key] = await fetchData(value)
		}
	}))
	return store
}

if (!sessionStorage.getItem("data")) {
	const getData = fetchData(films)
	console.log(getData)
	setTimeout(() => {
		sessionStorage.setItem("data", JSON.stringify(getData))
	}, 2000);
}

